; NOTE: comments marked [AI] are machine-generated by claude-opus-4-8 from the code alone
; and may be inaccurate; treat them as hints, not verified annotation. Comments marked
; [DOC <manual> <page>] have been reconciled against the primary-source Microsoft SoftCard
; manuals (CP/M 2.20, (C) 1980) and are authoritative: S&HD = "Software and Hardware
; Details", CPMREF = the CP/M 2.2 Reference Manual. See the consolidated fact sheet at
; ../../docs/CPM_Manual_Reconcile_Facts.md. This is the 2.23 / 44K 6502 stage-2 loader;
; the manual documents 2.20, so any 2.23-only feature (notably the Pascal-1.1 / device-6
; branch) is flagged as a post-1980 extension, NOT carried as a [DOC] manual citation.
;
; [AI] DECOMPILE OVERVIEW (independent decode of loader_223.bin, $0800-$13FF):
;   This 3072-byte image is the 2.23 / 44K SoftCard boot image. It holds FIVE distinct
;   bodies of code/data, several of which run at an address DIFFERENT from where they sit
;   in this file, and two of which are executed by the Z-80, not the 6502. The two Z-80
;   bodies are real Z-80 source sub-assembled by sjasmplus and INCBIN'd here (the
;   CPM_RPC6502 pattern with the CPUs swapped); everything else is decoded 6502 source:
;     (1) $0800-$0837  6502  stage dispatcher (runs in place at $0800).
;     (2) $0A00-$0FFF  6502  an Apple DOS 3.3-style RWTS, but it RUNS AT $BA00-$BFFF
;                            (language-card RAM). LOAD_CPM copies these six pages there
;                            with PAGE_COPY before use; every JSR inside it targets a
;                            $BAxx/$BBxx/$BExx/$BFxx run-address, never the $0Axx store
;                            address. Decoded here at its store address; the instruction
;                            stream is identical either way.
;     (3) $0C39-$0D4A  Z-80  a Z-80 routine embedded inside the RWTS page image (it lives
;                            in LC RAM at $BC39 after the copy, interleaved with the 6502
;                            nibble tables that physically follow at $BD5A/$BD9A). It is
;                            executed by the Z-80 CPU after the handoff, NOT by the 6502.
;                            Assembled from CPM_BootLoader_DiskXlate.asm and INCBIN'd.
;     (4) $11B1-$11BD  Z-80  the slot-probe handshake (Z80_BOOT_STUB), copied to $1000 and
;                            run by the Z-80 to clear the $3E "found" flag and bounce back.
;                            Assembled from CPM_BootLoader_ProbeOvl.asm and INCBIN'd.
;     (5) $1200-$13FF  6502  the install image: data copied to $0200-$03FF by LOAD_CPM. Its
;                            tail ($13C0-$13FF -> $03C0-$03FF) is the 6502 RPC service loop,
;                            written below as real 6502 instructions (it assembles at $13C0
;                            but RUNS AT $03C0/$03D2; every operand is absolute, so the bytes
;                            are identical at either address).
;   The real entry is LOAD_CPM ($1000), reached from the stage dispatcher. The slot probe,
;   LOAD_CPM disk read, page-2/3 install, and the Z-80 CPU handoff all live there.

; Range:  $0800-$13FF  (3072 bytes)

.setcpu "6502"
.segment "CODE"

; --- emit a high-bit (Apple "screen") ASCII string literal, byte-for-byte ---
.macro  ASCHI str
        .repeat .strlen(str), i
                .byte   .strat(str, i) | $80
        .endrep
.endmacro

; -- External symbols --
H2                   = $002C             ; End column for horizontal line / right edge for HLINE
A2L                  = $003E             ; General-purpose pointer 2 low (MOVE/VERIFY source end)
IN                   = $0200             ; GETLN input buffer ($0200-$02FF)
DOSRWA               = $03E3             ; DOS RWTS IOB address
SCRN_HOLE_0478_S0    = $0478             ; Screen-hole base; slot N adds N (e.g. slot 3 -> $047B). Per-card use varies; Videx firmware uses $0478+N as CRFLAG
SCRN_HOLE_04F8_S0    = $04F8             ; Screen-hole; slot N -> $04F8+N
SCRN_HOLE_0578_S0    = $0578             ; Screen-hole; slot N -> $0578+N
SCRN_HOLE_05F8_S0    = $05F8             ; Screen-hole; slot N -> $05F8+N. Pascal protocol byte 5 (status bits) per Tech Note Misc #8 lives here for slot N
SCRN_HOLE_0678_S0    = $0678             ; Screen-hole; slot N -> $0678+N
SCRN_HOLE_06F8_S0    = $06F8             ; Screen-hole; slot N -> $06F8+N
KBD                  = $C000             ; Read: keyboard data (high bit set when key pending). IIe write: CLR80STORE
LC_RAM_BANK2_RD      = $C080             ; Language card: read RAM bank 2 ($D000-$DFFF), write protect
LC_ROM_BANK2_WR      = $C081             ; Language card: read ROM, write enable bank 2 (read twice to enable write)
LC_RAM_BANK2_RDWR    = $C083             ; Language card: read/write RAM bank 2 (read twice to enable write)
LC_RAM_BANK1_RD      = $C088             ; Language card: read RAM bank 1, write protect
LC_ROM_BANK1_WR      = $C089             ; Language card: read ROM, write enable bank 1
LC_ROM_RD2           = $C08A             ; Language card: read ROM, write protect (alias)
LC_RAM_BANK1_RDWR    = $C08B             ; Language card: read/write RAM bank 1
TEXT                 = $FB2F             ; Set text mode + reset window to full screen
COUT                 = $FDED             ; Output character A via (CSW). Default routes to COUT1 (screen)
SETKBD               = $FE89             ; Reset KSW to default keyboard input ($FD1B); CSWL,KSWL := $1B,$FD
SETVID               = $FE93             ; Reset CSW to default screen output ($FDF0); CSWL,CSWH := $F0,$FD
RESTORE              = $FF3F             ; Monitor: A,X,Y,P <- save area $45-$48 (RPC handoff)
SAVE                 = $FF4A             ; Monitor: A,X,Y,P,S -> save area $45-$49 (RPC handoff)
IORTS                = $FF58             ; Monitor: a bare RTS (known no-op / addressing probe)
PRERR                = $FF2D             ; Print 'ERR' + bell
MONZ                 = $FF65             ; Monitor entry (clear stack, print '*', GETLN, parse)

; -- Mid-instruction references (shown inline as cover+offset) --
;   $0F3F -> RWTS_MAIN_EXIT+1             6502 skip idiom: enters the operand of $24 at $0F3E
;   $0FBC -> RWTS_PRENIB_2+1             6502 skip idiom: enters the operand of $2C at $0FBB

.org $0800

        .byte   $01                                              ; $0800
; ============================================================================
; STAGE DISPATCHER  ($0800-$0837, runs in place)
; ============================================================================
; [AI] $0800 holds a single flag byte ($01); $0801 is the real entry, called
;      repeatedly from the slot-ROM disk trampoline as each track-0 sector is
;      read in. $27 counts entries: on the first pass after sector 9 ($27==9)
;      it builds an indirect vector A2L/A2H ($3E/$3F) = $Cn5C (boot slot ROM +
;      $5C, slot N = X/16). $00 is the stage counter; each call bumps it and,
;      until it reaches $0B, re-enters the slot ROM via JMP (A2L) to pull the
;      next sector. When $00 == $0B (all 11 stage-2 sectors loaded) it jumps to
;      LOAD_CPM. STAGE_SECTOR_TBL is the physical-sector order for the staged
;      reads (DOS 3.3 2:1 interleave).
STAGE_DISPATCH:
        LDA $27                      ; $0801  A5 27
        CMP #$09                     ; $0803  C9 09
        BNE STAGE_NEXT                   ; $0805  D0 13
        TXA                          ; $0807  8A
        LSR                          ; $0808  4A
        LSR                          ; $0809  4A
        LSR                          ; $080A  4A
        LSR                          ; $080B  4A
        ORA #$C0                     ; $080C  09 C0
        STA $3F                      ; $080E  85 3F
        LDA #$5C                     ; $0810  A9 5C
        STA $3E                      ; $0812  85 3E
        LDA #$00                     ; $0814  A9 00
        STA $00                      ; $0816  85 00
        INC $27                      ; $0818  E6 27
STAGE_NEXT:
        INC $00                      ; $081A  E6 00
        LDY $00                      ; $081C  A4 00
        CPY #$0B                     ; $081E  C0 0B
        BNE STAGE_JUMP                   ; $0820  D0 03
        JMP LOAD_CPM                   ; $0822  4C 00 10
STAGE_JUMP:
        LDA STAGE_SECTOR_TBL,Y                 ; $0825  B9 2D 08
        STA $3D                      ; $0828  85 3D
        JMP (A2L)                    ; $082A  6C 3E 00
; [AI] Physical-sector fetch order for the staged track-0 reads, then the
;      sign-on string ".COPYRIGHT (C) 1982 MICROSOFT - CP" (the 2.23 banner; the
;      leading 1980/NK fragment is prior on-disk text the loader overwrites).
;      Followed by $00 fill to the end of the boot sector image.
STAGE_SECTOR_TBL:
        .byte   $00, $02, $04, $06, $08, $0A, $0C, $0E, $01, $03, $05, $07, $09, $0B, $0D, $0F ; $082D
; Sign-on banner. A high-bit fragment of the 1980/NK build banner (prior on-disk
; text the 2.23 build left in place) immediately followed by the live low-bit
; 1982/CP banner, then a $00 terminator.
BANNER:
        ASCHI   " COPYRIGHT (C) 1980 MICROSOFT - NK "   ; $083D  high-bit (overwritten 1980/NK)
        .byte   " COPYRIGHT (C) 1982 MICROSOFT - CP "   ; $0860  low-bit (live 1982/CP banner)
        .byte   $00                                     ; $0883  terminator
        .res    380, $00    ; $0884  fill
; ============================================================================
; RWTS  ($0A00-$0FFF in this file == RUNS AT $BA00-$BFFF in LC RAM)
; ============================================================================
; [AI] A standard Apple DOS 3.3 Read/Write Track Sector package. LOAD_CPM copies
;      these six pages to $BA00 (PAGE_COPY) before calling them, so every label
;      below is decoded at its STORE address ($0Axx) while the code actually
;      EXECUTES at run-address +$B000 ($BA00). All internal JSR/JMP operands you
;      see as bare $BAxx/$BBxx/$BExx/$BFxx are those run-addresses.
;
; [AI] RWTS_WRITE ($BA00): write one sector. Sends the self-sync field, the D5 AA AD
;      address prologue, the 6-and-2 encoded data from the $0900/$0C00 buffers via
;      the write-translate table at $BD5A, then the DE AA EB epilogue.
RWTS_WRITE:
        SEC                          ; $0A00  38
        STX $27                      ; $0A01  86 27
        STX SCRN_HOLE_0678_S0        ; $0A03  8E 78 06
        LDA $C08D,X                  ; $0A06  BD 8D C0
        LDA $C08E,X                  ; $0A09  BD 8E C0
        BMI RWTS_WRITE_DONE                   ; $0A0C  30 7C
        LDA $0C00                    ; $0A0E  AD 00 0C
        STA $26                      ; $0A11  85 26
        LDA #$FF                     ; $0A13  A9 FF
        STA $C08F,X                  ; $0A15  9D 8F C0
        ORA $C08C,X                  ; $0A18  1D 8C C0
        PHA                          ; $0A1B  48
        PLA                          ; $0A1C  68
        NOP                          ; $0A1D  EA
        LDY #$04                     ; $0A1E  A0 04
RWTS_WRITE_1:
        PHA                          ; $0A20  48
        PLA                          ; $0A21  68
        JSR $BA90                    ; $0A22  20 90 BA
        DEY                          ; $0A25  88
        BNE RWTS_WRITE_1                   ; $0A26  D0 F8
        LDA #$D5                     ; $0A28  A9 D5
        JSR $BA8F                    ; $0A2A  20 8F BA
        LDA #$AA                     ; $0A2D  A9 AA
        JSR $BA8F                    ; $0A2F  20 8F BA
        LDA #$AD                     ; $0A32  A9 AD
        JSR $BA8F                    ; $0A34  20 8F BA
        TYA                          ; $0A37  98
        LDY #$56                     ; $0A38  A0 56
        BNE RWTS_WRITE_3                   ; $0A3A  D0 03
RWTS_WRITE_2:
        LDA $0C00,Y                  ; $0A3C  B9 00 0C
RWTS_WRITE_3:
        EOR $0BFF,Y                  ; $0A3F  59 FF 0B
        TAX                          ; $0A42  AA
        LDA $BD5A,X                  ; $0A43  BD 5A BD
        LDX $27                      ; $0A46  A6 27
        STA $C08D,X                  ; $0A48  9D 8D C0
        LDA $C08C,X                  ; $0A4B  BD 8C C0
        DEY                          ; $0A4E  88
        BNE RWTS_WRITE_2                   ; $0A4F  D0 EB
        LDA $26                      ; $0A51  A5 26
        NOP                          ; $0A53  EA
RWTS_WRITE_4:
        EOR $0900,Y                  ; $0A54  59 00 09
        TAX                          ; $0A57  AA
        LDA $BD5A,X                  ; $0A58  BD 5A BD
        LDX SCRN_HOLE_0678_S0        ; $0A5B  AE 78 06
        STA $C08D,X                  ; $0A5E  9D 8D C0
        LDA $C08C,X                  ; $0A61  BD 8C C0
        LDA $0900,Y                  ; $0A64  B9 00 09
        INY                          ; $0A67  C8
        BNE RWTS_WRITE_4                   ; $0A68  D0 EA
        TAX                          ; $0A6A  AA
        LDA $BD5A,X                  ; $0A6B  BD 5A BD
        LDX $27                      ; $0A6E  A6 27
        JSR $BA92                    ; $0A70  20 92 BA
        LDA #$DE                     ; $0A73  A9 DE
        JSR $BA8F                    ; $0A75  20 8F BA
        LDA #$AA                     ; $0A78  A9 AA
        JSR $BA8F                    ; $0A7A  20 8F BA
        LDA #$EB                     ; $0A7D  A9 EB
        JSR $BA8F                    ; $0A7F  20 8F BA
        LDA #$FF                     ; $0A82  A9 FF
        JSR $BA8F                    ; $0A84  20 8F BA
        LDA $C08E,X                  ; $0A87  BD 8E C0
RWTS_WRITE_DONE:
        LDA $C08C,X                  ; $0A8A  BD 8C C0
        RTS                          ; $0A8D  60
RWTS_NIB_NOP:
        NOP                          ; $0A8E  EA
; [AI] $BA8F/$BA90/$BA92: write-a-nibble helpers (timed PHA/PLA pad + STA $C08D,X
;      to the data latch). Entered with carry management to control bit timing.
RWTS_NIB_CLC:
        CLC                          ; $0A8F  18
RWTS_NIB_DLY:
        PHA                          ; $0A90  48
        PLA                          ; $0A91  68
RWTS_NIB_OUT:
        STA $C08D,X                  ; $0A92  9D 8D C0
        ORA $C08C,X                  ; $0A95  1D 8C C0
        RTS                          ; $0A98  60
; [AI] RWTS_READADDR ($BA99): spin on the data latch ($C08C,X) to find and verify the
;      D5 AA 96 address field, decode track/sector/volume/checksum (4-and-4), and
;      confirm the DE AA epilogue. Returns carry set on any mismatch/timeout.
RWTS_READADDR:
        LDY #$20                     ; $0A99  A0 20
RWTS_READADDR_1:
        DEY                          ; $0A9B  88
        BEQ RWTS_READADDR_ERR                   ; $0A9C  F0 63
RWTS_READADDR_2:
        LDA $C08C,X                  ; $0A9E  BD 8C C0
        BPL RWTS_READADDR_2                   ; $0AA1  10 FB
RWTS_READADDR_3:
        EOR #$D5                     ; $0AA3  49 D5
        BNE RWTS_READADDR_1                   ; $0AA5  D0 F4
        NOP                          ; $0AA7  EA
RWTS_READADDR_4:
        LDA $C08C,X                  ; $0AA8  BD 8C C0
        BPL RWTS_READADDR_4                   ; $0AAB  10 FB
        CMP #$AA                     ; $0AAD  C9 AA
        BNE RWTS_READADDR_3                   ; $0AAF  D0 F2
        LDY #$56                     ; $0AB1  A0 56
RWTS_READADDR_5:
        LDA $C08C,X                  ; $0AB3  BD 8C C0
        BPL RWTS_READADDR_5                   ; $0AB6  10 FB
        CMP #$AD                     ; $0AB8  C9 AD
        BNE RWTS_READADDR_3                   ; $0ABA  D0 E7
        NOP                          ; $0ABC  EA
        NOP                          ; $0ABD  EA
        LDA #$00                     ; $0ABE  A9 00
RWTS_READADDR_6:
        DEY                          ; $0AC0  88
        STY $26                      ; $0AC1  84 26
RWTS_READADDR_7:
        LDY $C08C,X                  ; $0AC3  BC 8C C0
        BPL RWTS_READADDR_7                   ; $0AC6  10 FB
        EOR $BD04,Y                  ; $0AC8  59 04 BD
        LDY $26                      ; $0ACB  A4 26
        STA $0C00,Y                  ; $0ACD  99 00 0C
        BNE RWTS_READADDR_6                   ; $0AD0  D0 EE
RWTS_READADDR_8:
        STY $26                      ; $0AD2  84 26
RWTS_READADDR_9:
        LDY $C08C,X                  ; $0AD4  BC 8C C0
        BPL RWTS_READADDR_9                   ; $0AD7  10 FB
        EOR $BD04,Y                  ; $0AD9  59 04 BD
        LDY $26                      ; $0ADC  A4 26
        STA $0900,Y                  ; $0ADE  99 00 09
        INY                          ; $0AE1  C8
        BNE RWTS_READADDR_8                   ; $0AE2  D0 EE
RWTS_READADDR_10:
        LDY $C08C,X                  ; $0AE4  BC 8C C0
        BPL RWTS_READADDR_10                   ; $0AE7  10 FB
        CMP $BD04,Y                  ; $0AE9  D9 04 BD
        BNE RWTS_READADDR_ERR                   ; $0AEC  D0 13
RWTS_READADDR_11:
        LDA $C08C,X                  ; $0AEE  BD 8C C0
        BPL RWTS_READADDR_11                   ; $0AF1  10 FB
        CMP #$DE                     ; $0AF3  C9 DE
        BNE RWTS_READADDR_ERR                   ; $0AF5  D0 0A
        NOP                          ; $0AF7  EA
RWTS_READADDR_12:
        LDA $C08C,X                  ; $0AF8  BD 8C C0
        BPL RWTS_READADDR_12                   ; $0AFB  10 FB
        CMP #$AA                     ; $0AFD  C9 AA
        BEQ RWTS_READDATA_OK                   ; $0AFF  F0 5C
RWTS_READADDR_ERR:
        SEC                          ; $0B01  38
        RTS                          ; $0B02  60
; [AI] RWTS_READDATA ($BB03): find the D5 AA AD data prologue, read 342 6-and-2 nibbles
;      into the $0900/$0C00 buffers de-translating through the read table at $BD04
;      (indexed by disk byte $96..$FF), verify the data checksum + DE AA epilogue.
RWTS_READDATA:
        LDY #$FC                     ; $0B03  A0 FC
        STY $26                      ; $0B05  84 26
RWTS_READDATA_1:
        INY                          ; $0B07  C8
        BNE RWTS_READDATA_2                   ; $0B08  D0 04
        INC $26                      ; $0B0A  E6 26
        BEQ RWTS_READADDR_ERR                   ; $0B0C  F0 F3
RWTS_READDATA_2:
        LDA $C08C,X                  ; $0B0E  BD 8C C0
        BPL RWTS_READDATA_2                   ; $0B11  10 FB
RWTS_READDATA_3:
        CMP #$D5                     ; $0B13  C9 D5
        BNE RWTS_READDATA_1                   ; $0B15  D0 F0
        NOP                          ; $0B17  EA
RWTS_READDATA_4:
        LDA $C08C,X                  ; $0B18  BD 8C C0
        BPL RWTS_READDATA_4                   ; $0B1B  10 FB
        CMP #$AA                     ; $0B1D  C9 AA
        BNE RWTS_READDATA_3                   ; $0B1F  D0 F2
        LDY #$03                     ; $0B21  A0 03
RWTS_READDATA_5:
        LDA $C08C,X                  ; $0B23  BD 8C C0
        BPL RWTS_READDATA_5                   ; $0B26  10 FB
        CMP #$96                     ; $0B28  C9 96
        BNE RWTS_READDATA_3                   ; $0B2A  D0 E7
        LDA #$00                     ; $0B2C  A9 00
RWTS_READDATA_6:
        STA $27                      ; $0B2E  85 27
RWTS_READDATA_7:
        LDA $C08C,X                  ; $0B30  BD 8C C0
        BPL RWTS_READDATA_7                   ; $0B33  10 FB
        ROL                          ; $0B35  2A
        STA $26                      ; $0B36  85 26
RWTS_READDATA_8:
        LDA $C08C,X                  ; $0B38  BD 8C C0
        BPL RWTS_READDATA_8                   ; $0B3B  10 FB
        AND $26                      ; $0B3D  25 26
        STA H2,Y                     ; $0B3F  99 2C 00
        EOR $27                      ; $0B42  45 27
        DEY                          ; $0B44  88
        BPL RWTS_READDATA_6                   ; $0B45  10 E7
        TAY                          ; $0B47  A8
        BNE RWTS_READADDR_ERR                   ; $0B48  D0 B7
RWTS_READDATA_9:
        LDA $C08C,X                  ; $0B4A  BD 8C C0
        BPL RWTS_READDATA_9                   ; $0B4D  10 FB
        CMP #$DE                     ; $0B4F  C9 DE
        BNE RWTS_READADDR_ERR                   ; $0B51  D0 AE
        NOP                          ; $0B53  EA
RWTS_READDATA_10:
        LDA $C08C,X                  ; $0B54  BD 8C C0
        BPL RWTS_READDATA_10                   ; $0B57  10 FB
        CMP #$AA                     ; $0B59  C9 AA
        BNE RWTS_READADDR_ERR                   ; $0B5B  D0 A4
RWTS_READDATA_OK:
        CLC                          ; $0B5D  18
        RTS                          ; $0B5E  60
; [AI] RWTS_SEEK ($BB5F): move the head to the track in A. Compares against the current
;      track (screen-hole $0478+slot), energizes the stepper phases in sequence with the
;      RWTS_PHASEON/RWTS_PHASEXY helpers, timing each step from the step on/off-time
;      tables at $BBD1/$BBDD and RWTS_DELAY ($BBBC).
RWTS_SEEK:
        STX $2B                      ; $0B5F  86 2B
        STA $2A                      ; $0B61  85 2A
        CMP SCRN_HOLE_0478_S0        ; $0B63  CD 78 04
        BEQ RWTS_PHASE_RTS                   ; $0B66  F0 53
        LDA #$00                     ; $0B68  A9 00
        STA $26                      ; $0B6A  85 26
RWTS_SEEK_1:
        LDA SCRN_HOLE_0478_S0        ; $0B6C  AD 78 04
        STA $27                      ; $0B6F  85 27
        SEC                          ; $0B71  38
        SBC $2A                      ; $0B72  E5 2A
        BEQ RWTS_SEEK_DONE                   ; $0B74  F0 33
        BCS RWTS_SEEK_2                   ; $0B76  B0 07
        EOR #$FF                     ; $0B78  49 FF
        INC SCRN_HOLE_0478_S0        ; $0B7A  EE 78 04
        BCC RWTS_SEEK_3                   ; $0B7D  90 05
RWTS_SEEK_2:
        ADC #$FE                     ; $0B7F  69 FE
        DEC SCRN_HOLE_0478_S0        ; $0B81  CE 78 04
RWTS_SEEK_3:
        CMP $26                      ; $0B84  C5 26
        BCC RWTS_SEEK_4                   ; $0B86  90 02
        LDA $26                      ; $0B88  A5 26
RWTS_SEEK_4:
        CMP #$0C                     ; $0B8A  C9 0C
        BCS RWTS_SEEK_5                   ; $0B8C  B0 01
        TAY                          ; $0B8E  A8
RWTS_SEEK_5:
        SEC                          ; $0B8F  38
        JSR $BBAD                    ; $0B90  20 AD BB
        LDA $BBD1,Y                  ; $0B93  B9 D1 BB
        JSR $BBBC                    ; $0B96  20 BC BB
        LDA $27                      ; $0B99  A5 27
        CLC                          ; $0B9B  18
        JSR $BBB0                    ; $0B9C  20 B0 BB
        LDA $BBDD,Y                  ; $0B9F  B9 DD BB
        JSR $BBBC                    ; $0BA2  20 BC BB
        INC $26                      ; $0BA5  E6 26
        BNE RWTS_SEEK_1                   ; $0BA7  D0 C3
RWTS_SEEK_DONE:
        JSR $BBBC                    ; $0BA9  20 BC BB
        CLC                          ; $0BAC  18
RWTS_PHASEON:
        LDA SCRN_HOLE_0478_S0        ; $0BAD  AD 78 04
RWTS_PHASEXY:
        AND #$03                     ; $0BB0  29 03
        ROL                          ; $0BB2  2A
