; [AI] RWTS_XLATE / RWTS_XLATE_BUF ($BF53/$BF5B): swap the active buffer-pointer /
;      current-track between the primary ($0478+slot) and alternate ($04F8+slot)
;      screen-hole sets as the multi-sector read advances. RWTS_SLOT_TO_Y derives the
;      slot index (X/16) into Y.
RWTS_XLATE:
        ASL                          ; $0F53  0A
        JSR $BF5B                    ; $0F54  20 5B BF
        LSR SCRN_HOLE_0478_S0        ; $0F57  4E 78 04
        RTS                          ; $0F5A  60
RWTS_XLATE_BUF:
        STA $2E                      ; $0F5B  85 2E
        JSR $BF7E                    ; $0F5D  20 7E BF
        LDA SCRN_HOLE_0478_S0,Y      ; $0F60  B9 78 04
