        BPL RWTS_XLATE_3                   ; $0F76  10 03
RWTS_XLATE_2:
        STA SCRN_HOLE_0478_S0,Y      ; $0F78  99 78 04
RWTS_XLATE_3:
        JMP $BB5F                    ; $0F7B  4C 5F BB
RWTS_SLOT_TO_Y:
        TXA                          ; $0F7E  8A
        LSR                          ; $0F7F  4A
        LSR                          ; $0F80  4A
        LSR                          ; $0F81  4A
        LSR                          ; $0F82  4A
        TAY                          ; $0F83  A8
        RTS                          ; $0F84  60
RWTS_SET_BUF:
        PHA                          ; $0F85  48
        LDA $03E4                    ; $0F86  AD E4 03
        ROR                          ; $0F89  6A
        ROR $35                      ; $0F8A  66 35
        JSR $BF7E                    ; $0F8C  20 7E BF
        PLA                          ; $0F8F  68
        ASL                          ; $0F90  0A
        BIT $35                      ; $0F91  24 35
        BMI RWTS_SET_BUF_1                   ; $0F93  30 05
