; ============================================================================
; LOAD_CPM  ($1000, runs in place) -- the real stage-2 entry
; ============================================================================
; [AI] Reached from the stage dispatcher once all 11 track-0 sectors are in. Bank in
;      LC RAM, clear this slot two current-track screen-holes, reset TEXT/video/kbd
;      and the stack. Recover the boot slot from X (X/16); the 44K 2.23 build requires
;      slot 6 -- any other slot prints MSG_SLOT_SIX and drops to the monitor.
; [DOC Vol1 1-3/1-4 ; facts sec.8.9] Apple CP/M's slot function assignments fix the
;      A:/B: disk controller in slot 6 and require it to be present, so cold boot must
;      come from the slot-6 controller -- the precondition this slot==6 check enforces.
LOAD_CPM:
        LDA LC_ROM_BANK2_WR          ; $1000  AD 81 C0
        LDA LC_ROM_BANK2_WR          ; $1003  AD 81 C0
        TXA                          ; $1006  8A
        LSR                          ; $1007  4A
        LSR                          ; $1008  4A
        LSR                          ; $1009  4A
        LSR                          ; $100A  4A
        TAY                          ; $100B  A8
        PHA                          ; $100C  48
        STA LC_RAM_BANK1_RD,X        ; $100D  9D 88 C0
        LDA #$00                     ; $1010  A9 00
        STA SCRN_HOLE_0478_S0,Y      ; $1012  99 78 04
        STA SCRN_HOLE_04F8_S0,Y      ; $1015  99 F8 04
        JSR TEXT                     ; $1018  20 2F FB
        JSR SETVID                   ; $101B  20 93 FE
        JSR SETKBD                   ; $101E  20 89 FE
        PLA                          ; $1021  68
        LDX #$FF                     ; $1022  A2 FF
        TXS                          ; $1024  9A
        CMP #$06                     ; $1025  C9 06
        BEQ LOAD_CPM_GO                   ; $1027  F0 10
        LDY #$00                     ; $1029  A0 00
LOAD_CPM_SLOTMSG:
        LDA MSG_SLOT_SIX,Y                 ; $102B  B9 92 11
        BEQ LOAD_CPM_ABORT                   ; $102E  F0 06
        JSR COUT                     ; $1030  20 ED FD
        INY                          ; $1033  C8
        BNE LOAD_CPM_SLOTMSG                   ; $1034  D0 F5
LOAD_CPM_ABORT:
        JMP MONZ                     ; $1036  4C 65 FF
LOAD_CPM_GO:
        LDY #$0E                     ; $1039  A0 0E
; [AI] Copy the 14-byte Z80_BOOT_STUB to $0FFF (just below the RWTS image): the tiny
;      Z-80 fragment the SoftCard executes at handoff. Then install the page-2/page-3
;      image: $1200-$12FF -> $0200-$02FF and $1300-$13F0 -> $0300-$03F0.
COPY_Z80_STUB:
        LDA Z80_BOOT_STUB,Y                 ; $103B  B9 B0 11
        STA $0FFF,Y                  ; $103E  99 FF 0F
        DEY                          ; $1041  88
        BNE COPY_Z80_STUB                   ; $1042  D0 F7
COPY_INSTALL_LO:
        LDA $1200,Y                  ; $1044  B9 00 12
        STA IN,Y                     ; $1047  99 00 02
        DEY                          ; $104A  88
        BNE COPY_INSTALL_LO                   ; $104B  D0 F7
        LDY #$F1                     ; $104D  A0 F1
COPY_INSTALL_HI:
        LDA $12FF,Y                  ; $104F  B9 FF 12
        STA $02FF,Y                  ; $1052  99 FF 02
        DEY                          ; $1055  88
        BNE COPY_INSTALL_HI                   ; $1056  D0 F7
        STY $03B8                    ; $1058  8C B8 03
        STY $3C                      ; $105B  84 3C
        DEY                          ; $105D  88
        STY $3E                      ; $105E  84 3E
        LDY #$C7                     ; $1060  A0 C7
; [AI] SLOTSCAN ($1062): the SoftCard / peripheral slot probe. For each slot 7..1 it
;      checksums the slot ROM (SLOT_CHECKSUM, 256-byte add) to locate the SoftCard (the
;      $3E found flag + its $03C7/$03DE control-address fields get set at
;      SLOTSCAN_SOFTCARD), and classifies every card by matching ROM ID bytes at offset
;      5 and 7 against SIG_BYTE5_TBL/SIG_BYTE7_TBL, writing a device code into the
;      Card-Type byte for the slot ($02F8+slot) and bumping the disk-controller count
;      at $03B8 for Disk II matches.
; [DOC S&HD 2-26/2-27] The per-slot detected-card byte forms the Card Type Table
;      (manual symbol SLTTYP, Z-80 $F3B9 = 6502 $03B9; entry for slot S at $03B8+S),
;      with the Disk Count Byte (controllers x2) at $03B8. [DOC S&HD 2-26/2-27 ; facts sec.3.6] Values:
;      0=no ROM, 1=ROM unknown, 2=Apple Disk II, 3=Apple Comms/CCS 7710A serial,
;      4=Apple High-Speed Serial / Videx Videoterm / M&R Sup-R-Term / Silentype,
;      5=Apple Parallel Printer.
SLOTSCAN:
        STY $3D                      ; $1062  84 3D
        STY $1069                    ; $1064  8C 69 10
        STA KBD                      ; $1067  8D 00 C0
        LDA $3E                      ; $106A  A5 3E
        BEQ SLOTSCAN_SOFTCARD                   ; $106C  F0 18
        JSR SLOT_CHECKSUM                 ; $106E  20 4E 11
        STA $40                      ; $1071  85 40
        STX $41                      ; $1073  86 41
        JSR SLOT_CHECKSUM                 ; $1075  20 4E 11
        CPX #$00                     ; $1078  E0 00
        BEQ SLOTSCAN_NONE                   ; $107A  F0 1E
        CMP $40                      ; $107C  C5 40
        BNE SLOTSCAN_NONE                   ; $107E  D0 1A
        CPX $41                      ; $1080  E4 41
        BEQ SLOTSCAN_TYPE                   ; $1082  F0 1A
        BNE SLOTSCAN_NONE                   ; $1084  D0 14
; [DOC S&HD 2-24/2-25 ; facts sec.4.3] $03DE/$03DF is Z$CPU, the SoftCard-location cell
;      (Z-80 $F3DE): the loader plants low byte = 0 ($03DE) and high byte = $En = found
;      slot $Cn + $20 ($03DF), the form a later WRITE uses to switch CPUs.
SLOTSCAN_SOFTCARD:
        INC $3E                      ; $1086  E6 3E
        STY $03C8                    ; $1088  8C C8 03
        LDA #$00                     ; $108B  A9 00
        STA $03C7                    ; $108D  8D C7 03
        STA $03DE                    ; $1090  8D DE 03   Z$CPU low byte = 0
        TYA                          ; $1093  98
        CLC                          ; $1094  18
        ADC #$20                     ; $1095  69 20       $Cn -> $En
        STA $03DF                    ; $1097  8D DF 03   Z$CPU high byte = $En (N = SoftCard slot)
SLOTSCAN_NONE:
        LDX #$00                     ; $109A  A2 00
        BEQ SLOTSCAN_STORE                   ; $109C  F0 2D
SLOTSCAN_TYPE:
        LDX #$04                     ; $109E  A2 04
SLOTSCAN_TYPE_1:
        LDY #$05                     ; $10A0  A0 05
        LDA ($3C),Y                  ; $10A2  B1 3C
        CMP SIG_BYTE5_TBL,X                 ; $10A4  DD BE 11
        BNE SLOTSCAN_TYPE_2                   ; $10A7  D0 09
        LDY #$07                     ; $10A9  A0 07
        LDA ($3C),Y                  ; $10AB  B1 3C
        CMP SIG_BYTE7_TBL,X                 ; $10AD  DD C2 11
        BEQ SLOTSCAN_TYPE_3                   ; $10B0  F0 03
SLOTSCAN_TYPE_2:
        DEX                          ; $10B2  CA
        BNE SLOTSCAN_TYPE_1                   ; $10B3  D0 EB
SLOTSCAN_TYPE_3:
        INX                          ; $10B5  E8
        CPX #$02                     ; $10B6  E0 02
        BNE SLOTSCAN_TYPE_4                   ; $10B8  D0 03
        INC $03B8                    ; $10BA  EE B8 03
; [AI] (2.23 EXTENSION, NOT in the 1980 manual) After a value-4 (High-Speed-Serial /
;      Videx-class) signature match, the 2.23 scan reads the slot Pascal-1.1 signature
;      byte at $Cn0B and, on a match (==$01), overrides the stored device code with 6.
;      The 2.20 loader lacks this branch. Per Apple ][ Tech Note Misc #8 this is a
;      Pascal-1.1 firmware probe, not Videx-specific; do not [DOC]-cite device 6.
SLOTSCAN_TYPE_4:
        CPX #$04                     ; $10BD  E0 04
        BNE SLOTSCAN_STORE                   ; $10BF  D0 0A
        LDY #$0B                     ; $10C1  A0 0B
        LDA ($3C),Y                  ; $10C3  B1 3C
        CMP #$01                     ; $10C5  C9 01
        BNE SLOTSCAN_STORE                   ; $10C7  D0 02
        LDX #$06                     ; $10C9  A2 06
SLOTSCAN_STORE:
        LDY $3D                      ; $10CB  A4 3D
        TXA                          ; $10CD  8A
        STA $02F8,Y                  ; $10CE  99 F8 02
        DEY                          ; $10D1  88
        CPY #$C0                     ; $10D2  C0 C0
        BNE SLOTSCAN                   ; $10D4  D0 8C
        ASL $03B8                    ; $10D6  0E B8 03
        LDA $3E                      ; $10D9  A5 3E
        CMP #$01                     ; $10DB  C9 01
        BEQ HANDOFF                   ; $10DD  F0 10
        LDY #$00                     ; $10DF  A0 00
NOSOFTCARD_MSG:
        LDA MSG_NO_SOFTCARD,Y                 ; $10E1  B9 73 11
        BEQ NOSOFTCARD_ABORT                   ; $10E4  F0 06
        JSR COUT                     ; $10E6  20 ED FD
        INY                          ; $10E9  C8
        BNE NOSOFTCARD_MSG                   ; $10EA  D0 F5
NOSOFTCARD_ABORT:
        JMP MONZ                     ; $10EC  4C 65 FF
; ============================================================================
; HANDOFF  ($10EF) -- copy runtime, relocate RWTS to $BA00, switch to the Z-80
; ============================================================================
; [AI] SoftCard found. Copy $13EF-$13FF -> $03EF (the page-3 control tail), then
;      self-modify this routine first 3 bytes at $1000 into JMP $FA00 (the Z-80 BIOS
;      warm-entry), so a later re-entry lands in CP/M. PAGE_COPY then relocates the
;      RWTS: $0A00 -> $BA00 (6 pages) and copies the rest of the RWTS image + the Z-80
;      disk glue into LC RAM (the $0A97 6-page and $0AA3 $17-page blocks), patching the
;      run-time constant at $BC08. JSR $BBEB re-inits the IOB.
HANDOFF:
        LDY #$10                     ; $10EF  A0 10
HANDOFF_1:
        LDA $13EF,Y                  ; $10F1  B9 EF 13
        STA $03EF,Y                  ; $10F4  99 EF 03
        DEY                          ; $10F7  88
        BNE HANDOFF_1                   ; $10F8  D0 F7
        LDA #$C3                     ; $10FA  A9 C3
        STA LOAD_CPM                   ; $10FC  8D 00 10
        LDA #$00                     ; $10FF  A9 00
        STA $1001                    ; $1101  8D 01 10
        LDA #$FA                     ; $1104  A9 FA
        STA $1002                    ; $1106  8D 02 10
        LDA #$0A                     ; $1109  A9 0A
        STA $53                      ; $110B  85 53
        LDA #$BA                     ; $110D  A9 BA
        STA $51                      ; $110F  85 51
        LDA #$00                     ; $1111  A9 00
        STA $52                      ; $1113  85 52
        STA $50                      ; $1115  85 50
        LDX #$06                     ; $1117  A2 06
        JSR PAGE_COPY                 ; $1119  20 5C 11
        LDA #$80                     ; $111C  A9 80
        JSR $BBEB                    ; $111E  20 EB BB
        LDA #$0A                     ; $1121  A9 0A
        STA $BC08                    ; $1123  8D 08 BC
        LDA #$97                     ; $1126  A9 97
        STA $53                      ; $1128  85 53
        LDA #$0A                     ; $112A  A9 0A
        STA $51                      ; $112C  85 51
        LDX #$06                     ; $112E  A2 06
        JSR PAGE_COPY                 ; $1130  20 5C 11
        LDA #$80                     ; $1133  A9 80
        STA $53                      ; $1135  85 53
        LDA #$A3                     ; $1137  A9 A3
        STA $51                      ; $1139  85 51
        LDX #$17                     ; $113B  A2 17
        JSR PAGE_COPY                 ; $113D  20 5C 11
        LDY #$06                     ; $1140  A0 06
; [AI] Copy 6 bytes from $116C to $FFF9 -> the $FFFA-$FFFF vectors (NMI/RESET/IRQ) all
;      point at $03C0, the RPC service loop. [DOC S&HD 2-25 ; facts sec.2.4/4.4] $03C0
;      (Z-80 $F3C0) is the documented start of the 6502->Z-80 mode-switch routine, and the
;      6502 RESET/NMI/BREAK vectors are specified to point here. [DOC S&HD 2-24/2-25 ;
;      facts sec.4.3] The actual CPU flip happens inside that loop by writing the SoftCard
;      control location (Z$CPU, $03DE = 6502 $F3DE) holding $Cn00 (N = SoftCard slot); the
;      write switches the bus to the Z-80. JMP $03D2 enters the loop and never returns to
;      6502 stage-2 code.
HANDOFF_VECS:
        LDA $116C,Y                  ; $1142  B9 6C 11
        STA $FFF9,Y                  ; $1145  99 F9 FF
        DEY                          ; $1148  88
        BNE HANDOFF_VECS                   ; $1149  D0 F7
        JMP $03D2                    ; $114B  4C D2 03
; [AI] SLOT_CHECKSUM ($114E): 256-byte additive checksum of the slot ROM at ($3C),
;      returning sum in A and carry-count in X (used to fingerprint the SoftCard ROM).
SLOT_CHECKSUM:
        LDA #$00                     ; $114E  A9 00
        TAX                          ; $1150  AA
        TAY                          ; $1151  A8
SLOT_CHECKSUM_1:
        CLC                          ; $1152  18
        ADC ($3C),Y                  ; $1153  71 3C
        BCC SLOT_CHECKSUM_2               ; $1155  90 01
        INX                          ; $1157  E8
SLOT_CHECKSUM_2:
        INY                          ; $1158  C8
        BNE SLOT_CHECKSUM_1               ; $1159  D0 F7
        RTS                          ; $115B  60
; [AI] PAGE_COPY ($115C): copy X pages from ($52) to ($50) (256 bytes each, high bytes
;      auto-incremented). Used to relocate the RWTS and the Z-80 glue into LC RAM.
PAGE_COPY:
        LDY #$00                     ; $115C  A0 00
PAGE_COPY_1:
        LDA ($52),Y                  ; $115E  B1 52
        STA ($50),Y                  ; $1160  91 50
        DEY                          ; $1162  88
        BNE PAGE_COPY_1               ; $1163  D0 F9
        INC $53                      ; $1165  E6 53
        INC $51                      ; $1167  E6 51
        DEX                          ; $1169  CA
        BNE PAGE_COPY                 ; $116A  D0 F0
        RTS                          ; $116C  60
        .byte   $C0, $03, $C0, $03, $C0, $03                     ; $116D
; [AI] Console messages (high-ASCII, $8D = CR, $00 terminator) and probe tables.
MSG_NO_SOFTCARD:
        .byte   $8D, $8D, $8D, $8D                               ; $1173  4x CR
        ASCHI   "CAN'T FIND Z80 SOFTCARD"                        ; $1177
        .byte   $8D                                             ; $118E  trailing CR
        .byte   $8D, $8D, $00                                    ; $118F  2x CR + terminator
MSG_SLOT_SIX:
        .byte   $8D, $8D, $8D, $8D                               ; $1192  4x CR
        ASCHI   "MUST BOOT FROM SLOT SIX"                        ; $1196
        .byte   $8D                                             ; $11AD  trailing CR
        .byte   $8D, $8D                                         ; $11AE  2x CR
; [AI] Z80_BOOT_STUB: the SoftCard slot-probe handshake. A leading $00 (the copy-loop's
;      index-0 cell, data, never copied) followed by 13 bytes of Z-80 code. COPY_Z80_STUB
;      moves $11B1..$11BE to $1000..$100D, over the loader's own startup region (the 6502
;      has finished with it). From then on those bytes run on the Z-80, never the 6502: the
;      SoftCard maps the Z-80 reset address ($0000) to Apple $1000, so the slot-probe write
;      (the self-modified STA KBD in SLOTSCAN) switches to the Z-80 and lands it at $1000,
;      where it clears the $3E "found" flag and bounces back. The 13 Z-80 bytes are assembled
;      from CPM_BootLoader_ProbeOvl.asm and INCBIN'd; the JR's offset byte ($F2) is the
;      following SIG_BYTE5_TBL[0] (so SAVEBIN stops at the JR opcode).
Z80_BOOT_STUB:
        .byte   $00                     ; $11B0  copy index-0 cell (data, not copied)
;   >>> CPM_BootLoader_ProbeOvl.asm -- verbatim listing of the INCBIN'd source (regen: inject_incbin_listing) >>>
;
; FOUND   EQU $F03E        ; the 6502's $3E "SoftCard found" flag (Z-80 view of $003E)
; PROBED  EQU $F03D        ; the probed slot's $Cn high byte, set by the 6502 ($003D)
;
;     ORG $1000
;
; PROBE_OVL:
;     XOR A                ; A = 0
;     LD (FOUND),A         ; $3E = 0 -> "SoftCard found in the probed slot"
;     LD L,A               ; HL low = 0
;     LD A,(PROBED)        ; A = probed slot $Cn
;     ADD A,$20            ; $Cn -> $En (the slot's Z-80 I/O page)
;     LD H,A               ; HL = $En00
;     LD (HL),A            ; touch $En00 -> Apple $Cn00 -> switch back to the 6502
;     JR PROBE_OVL         ; loop ($18; offset byte $F2 supplied by host SIG_BYTE5_TBL[0])
;   <<< end listing <<<
        .incbin "CPM_BootLoader_ProbeOvl.bin"   ; $11B1-$11BD  (Z-80; JR offset = SIG_BYTE5_TBL[0])
; [AI] SIG_BYTE5_TBL / SIG_BYTE7_TBL: the slot-ROM ID bytes (ROM offsets $05 and $07)
;      the probe matches to classify Disk II / serial / Videx-class / printer cards.
SIG_BYTE5_TBL:
        .byte   $F2, $03, $18, $38                               ; $11BE
SIG_BYTE7_TBL:
        .byte   $48, $3C, $38, $18, $48                          ; $11C2

; ============================================================================
; INSTALL IMAGE  ($1200-$13FF in file -> copied to $0200-$03FF by LOAD_CPM)
; ============================================================================
; [AI] $1200-$137F is $00 fill: it becomes page-2 ($0200-$027F, the input buffer
;      area) that CP/M reuses. The 441-byte .res below spans this image low half.
        .res    441, $00    ; $11C7  fill
; [DOC S&HD 2-18/2-19 ; facts sec.3.2] I/O Vector Table: eleven 2-byte BIOS character-I/O
;      vectors (low-high), copied with this image to $0380-$0395 (Z-80 $F380). Each BIOS
;      CONST/CONIN/CONOUT/READER/PUNCH/LIST primitive JMPs through one of these cells:
;        $0380 $FB14 Console Status   $0382 $FB33 Console In #1   $0384 $FB33 Console In #2
;        $0386 $FCB5 Console Out #1   $0388 $FCB5 Console Out #2  $038A $FE66 Reader In #1
;        $038C $FE66 Reader In #2     $038E $FE60 Punch Out #1    $0390 $FE60 Punch Out #2
;        $0392 $FE4C List Out #1      $0394 $FE4C List Out #2
        .byte   $14, $FB, $33, $FB, $33, $FB, $B5, $FC, $B5, $FC, $66, $FE, $66, $FE, $60, $FE ; $1380
; [DOC S&HD 2-14 ; facts sec.3.3] $0396/$0397 (this image $1396/$1397, Z-80 $F396/$F397):
;      software Cursor XY coordinate offset ($20) then lead-in character ($1B). The offset's
;      high bit selects X/Y transmission order; lead-in 0 = none.
; [DOC S&HD 2-14/2-15 ; facts sec.3.4] Software screen-function table (SSFTAB, Z-80 $F398),
;      base at $0398 (this image $1398): the 11-byte parallel-to-hardware match table CP/M
;      tests an incoming sequence against (entry 0 = function not implemented; high bit set =
;      lead-in required).
        .byte   $60, $FE, $4C, $FE, $4C, $FE, $20, $1B, $AA, $D9, $D4, $A9, $A8, $1E, $BD, $0B ; $1390
; [DOC S&HD 2-14/2-15 ; facts sec.3.3/3.4] $03A1/$03A2 = hardware Cursor XY offset / lead-in
;      ($F3A1/$F3A2); $03A3-$03AB = the parallel Hardware screen-function table emitted to the
;      terminal once SSFTAB matches.
; [DOC S&HD 2-17 ; facts sec.3.5] Keyboard Character Redefinition Table at $03AC (Z-80 $F3AC,
;      this image $13AC): up to six 2-byte {redefine-from, redefine-to} ASCII pairs (high bits
;      cleared), terminated by a byte with the high bit set if fewer than six. Applies to
;      TTY:/CRT: input only.
        .byte   $0C, $A0, $00, $0C, $0B, $1D, $0E, $0F, $19, $1E, $1F, $1C, $0B, $5B, $00, $7F ; $13A0
        .byte   $02, $5C, $15, $09, $FF, $FF, $FF, $FF           ; $13B0
        .res    8, $00    ; $13B8  fill
; [AI] RPC SERVICE LOOP image  ($13C0-$13DB in file -> $03C0-$03DB at run time).
;      6502 code copied to $03C0 by HANDOFF and entered by the final JMP $03D2 (it
;      then loops at $03C0 forever, servicing Z-80 disk requests: flip to the 6502,
;      run RWTS, flip back). Written below as real instructions: it RUNS at $03C0
;      but is assembled here in the install image and copied there. Every operand
;      is absolute, so the bytes are identical at either address, and the self-loop
;      JMP target stays the literal runtime $03C0 (not this $13C0 image copy). The
;      STA $FFFF operand is patched at runtime to $Cn00 (N = SoftCard slot); that
;      write switches the bus to the Z-80.
; [DOC S&HD 2-25 ; facts sec.4.4] This $03C0 body is the documented 6502->Z-80
;      mode-switch routine (Z-80 $F3C0): the RESET/NMI/BREAK vectors point here, and it
;      hands the bus back to the Z-80.
        LDA LC_RAM_BANK2_RDWR           ; $03C0  AD 83 C0  bank LC RAM bank2 R/W
        LDA LC_RAM_BANK2_RDWR           ; $03C3  AD 83 C0   (two reads arm the LC write latch)
        ; [DOC S&HD 2-24/2-25 ; facts sec.2.5/4.3] operand patched to $Cn00 (the SoftCard's
        ;   slot-dependent control area / Z$CPU $03DE); a WRITE (not a read) there switches CPUs.
        STA $FFFF                       ; $03C6  8D FF FF  operand patched to $Cn00 -> switch to Z-80
        LDA LC_ROM_BANK2_WR             ; $03C9  AD 81 C0  bank ROM
        JSR $0E36                       ; $03CC  20 36 0E  into the RWTS read-byte spin (loader resident)
        JSR IORTS                       ; $03CF  20 58 FF  bare RTS (addressing probe / no-op)
        STA LC_ROM_BANK2_WR             ; $03D2  8D 81 C0  (resume here) bank ROM
        SEI                             ; $03D5  78
        ; [DOC S&HD 2-24/2-25 ; facts sec.4.1] save area $45-$49 are the RPC register-pass
        ;   cells (A=$45, Y=$46, X=$47, P=$48, 6502 SP at $49 on exit) the Z-80 reads back.
        JSR SAVE                        ; $03D6  20 4A FF  A,X,Y,P,S -> $45-$49 (results for Z-80)
        JMP $03C0                       ; $03D9  4C C0 03  loop -> hand the bus back to the Z-80
        .byte   $00, $20                                 ; $13DC  config cells (data)
        .res    9, $00    ; $13DE  fill
        .byte   $60                                              ; $13E7
        .res    8, $00    ; $13E8  fill
        .byte   $C0, $03, $C0, $03, $A6, $4C, $C0, $03, $4C, $C0, $03, $4C, $C0, $03, $C0, $03 ; $13F0
